// Parse the last 100 log entries and compute stats
const raw = $input.first().binary?.data
  ? Buffer.from($input.first().binary.data, 'base64').toString('utf-8')
  : $input.first().json?.data || '[]';

let entries = [];
try { entries = JSON.parse(raw); } catch { entries = []; }
if (!Array.isArray(entries)) entries = [];

const last100 = entries.slice(-100);

// Intent frequency
const intentCounts = {};
const intentTimes = {};
let failures = 0;

for (const e of last100) {
  const intent = e.intent || 'unknown';
  intentCounts[intent] = (intentCounts[intent] || 0) + 1;
  if (!intentTimes[intent]) intentTimes[intent] = [];
  intentTimes[intent].push(e.exec_time_ms || 0);
  if (e.success === false) failures++;
}

const avgTimes = {};
for (const [intent, times] of Object.entries(intentTimes)) {
  avgTimes[intent] = Math.round(times.reduce((a, b) => a + b, 0) / times.length);
}

const failurePct = last100.length > 0
  ? ((failures / last100.length) * 100).toFixed(1)
  : '0.0';

const recent10 = JSON.stringify(last100.slice(-10), null, 2);

const prompt = `You are analyzing performance logs for RUBE, an AI voice assistant.

Intent frequency (last ${last100.length} runs): ${JSON.stringify(intentCounts)}
Average response time per intent (ms): ${JSON.stringify(avgTimes)}
Overall failure rate: ${failurePct}%
10 most recent entries: ${recent10}

Return a JSON array of 3-5 concise, actionable suggestions the developer can use
to improve RUBE's reliability or speed. Plain strings only.
Return ONLY the JSON array. No other text.`;

return [{ json: { prompt, entryCount: last100.length } }];

// Extract and parse suggestions from Claude's response
const body = $input.first().json;
let text = '';
try {
  text = body.content[0].text.trim();
} catch {
  return [{ json: { suggestions: [] } }];
}

// Strip any accidental markdown fences
text = text.replace(/^```json\s*/i, '').replace(/```$/i, '').trim();

let suggestions = [];
try {
  suggestions = JSON.parse(text);
  if (!Array.isArray(suggestions)) suggestions = [];
} catch {
  suggestions = [];
}

return [{ json: { suggestions } }];
